    /// Returns the "other white" GC color bitmask.
    ///
    /// C: `otherwhite(g)` macro.
    /// macros.tsv: `otherwhite → g.other_white()`
    pub fn other_white(&self) -> u8 {
        // TODO(port): Phase D — toggle white bit properly
        self.currentwhite ^ 0x03
