    /// Object write barrier.
    ///
    /// C: `luaC_objbarrier(L, o, v)`.
    /// macros.tsv: `luaC_objbarrier → state.gc().obj_barrier(p, o)` — no-op
    pub fn obj_barrier(&self, _p: &dyn std::any::Any, _o: &dyn std::any::Any) {}

