const LUA_EXTRASPACE: usize = std::mem::size_of::<*mut ()>();

// C: GCSTPGC — GC stopped for state building (lgc.h constant)
// TODO(port): import from crate::gc (lgc.c → gc.rs) once it exists in Phase D
