// C: LUA_API int lua_pushthread (lua_State *L)
// Returns true if pushed thread is the main thread.
pub fn push_thread(state: &mut LuaState) -> bool {
    // C: setthvalue(L, s2v(L->top.p), L); api_incr_top(L);
